function getScore(subject) {
  return new Promise(resolve =>
    setTimeout(() => resolve({ subject, score: Math.floor(Math.random() * 40 + 60) }), 100)
  );
}

async function report() {
  try {
    const math = await getScore("Math");
    const english = await getScore("English");
    const avg = (math.score + english.score) / 2;
    console.log(`Math: ${math.score}, English: ${english.score}`);
    console.log(`Average: ${avg.toFixed(1)}`);
  } catch (err) {
    console.error("Failed:", err);
  }
}

report();

