    // 過濾偶數
    vector<int> evens;
    copy_if(nums.begin(), nums.end(), back_inserter(evens),
            [](int n) { return n % 2 == 0; });
    cout << "Evens: ";
    for (int x : evens) cout << x << " ";
    cout << "\n";

    // 自訂排序
    sort(nums.begin(), nums.end(), [](int a, int b) {
        return a % 3 < b % 3; // 按餘 3 的值排序
    });
    for (int x : nums) cout << x << " ";
    cout << "\n";
    return 0;
}

