{$APPTYPE CONSOLE}
type
  TAnimal = class
  private
    FName: string;
    FSound: string;
  public
    constructor Create(AName, ASound: string);
    procedure Speak;
    property Name: string read FName;
  end;

constructor TAnimal.Create(AName, ASound: string);
begin
  FName := AName;
  FSound := ASound;
end;

procedure TAnimal.Speak;
begin
  WriteLn(FName + ' says: ' + FSound);
end;

var
  Dog, Cat: TAnimal;
begin
  Dog := TAnimal.Create('Rex', 'Woof!');
  Cat := TAnimal.Create('Luna', 'Meow!');
  Dog.Speak;
  Cat.Speak;
  Dog.Free;
  Cat.Free;
  ReadLn;
end.

