type
  TPoint = record
    X, Y: Double;
    function Distance(Other: TPoint): Double;
    function ToString: string;
  end;

function TPoint.Distance(Other: TPoint): Double;
begin
  Result := Sqrt(Sqr(X - Other.X) + Sqr(Y - Other.Y));
end;

function TPoint.ToString: string;
begin
  Result := Format('(%.1f, %.1f)', [X, Y]);
end;

